function readUI(){["a","b"].forEach(function(w){var s=w==="a"?"A":"B";var nm=$("name"+s);if(nm)S[w].name=nm.value||S[w].name;var mb=$("mbti"+s);if(mb&&mb.value)S[w].mbti=mb.value;var en=$("ennea"+s);if(en&&en.value)S[w].ennea=en.value;var at=$("attach"+s);if(at&&at.value)S[w].attach=at.value;var llg=$("llGive"+s);if(llg&&llg.value)S[w].llGive=llg.value;var llr=$("llReceive"+s);if(llr&&llr.value)S[w].llReceive=llr.value;var cs=$("conflict"+s);if(cs&&cs.value)S[w].conflict=cs.value;var md=$("mood"+s);if(md&&md.value)S[w].mood=md.value;var sp=$("support"+s);if(sp)S[w].support=parseInt(sp.value,10);
["O","C","E","A","N"].forEach(function(d){var sl=$("ocean_"+d+s);if(sl)S[w].ocean[d]=parseFloat(sl.value)/100;});
D.MH_ORDER.forEach(function(mk){var sl=$("mh_"+mk+s);if(sl)S[w].mh[mk]=parseInt(sl.value,10);});});}
function wireProfileChanges(){["a","b"].forEach(function(w){var s=w==="a"?"A":"B";["mbti"+s,"ennea"+s,"attach"+s,"llGive"+s,"llReceive"+s,"conflict"+s,"mood"+s].forEach(function(id){var el=$(id);if(!el)return;el.addEventListener("change",function(){readUI();if(id==="mbti"+s){E.setOceanFromMBTI(w);var oc=S[w].ocean;["O","C","E","A","N"].forEach(function(d){var sl=$("ocean_"+d+s);if(sl)sl.value=Math.round(oc[d.toLowerCase()]*100);var vl=$("ov_"+d+s);if(vl)vl.textContent=Math.round(oc[d]*100)+"%";});}E.recalcAll();renderAll();updateSelTips(w);});});
var supEl=$("support"+s);if(supEl){supEl.addEventListener("input",function(){var v=parseInt(this.value,10);S[w].support=v;var lbl=D.getSupportLabel(v);var valEl=$("supportVal"+s);if(valEl)valEl.textContent=lbl.label;var tipEl=$("supportTip"+s);if(tipEl)tipEl.textContent=lbl.desc;E.recalcAll();renderAll();});}

["O","C","E","A","N"].forEach(function(d){var sl=$("ocean_"+d+s);if(sl)sl.addEventListener("input",function(){var vl=$("ov_"+d+s);if(vl)vl.textContent=this.value+"%";readUI();E.recalcAll();renderAll();});});
D.MH_ORDER.forEach(function(mk){var sl=$("mh_"+mk+s);if(sl){sl.addEventListener("input",function(){var lv=parseInt(this.value,10);var info=D.MH_LEVELS[lv];var tip=$("mhtip_"+mk+s);if(tip)tip.textContent=info?info.label+" \u2014 "+info.desc:"";var mhv=$("mhval_"+mk+s);if(mhv)mhv.textContent=lv>0?info.label:"None";readUI();E.recalcAll();renderAll();});}});});}
function updateSelTips(w){var s=w==="a"?"A":"B";var maps=[{id:"mbti"+s,src:D.MBTI,key:S[w].mbti},{id:"ennea"+s,src:D.ENNEA,key:S[w].ennea},{id:"attach"+s,src:D.ATT,key:S[w].attach},{id:"mood"+s,src:D.MOOD,key:S[w].mood}];maps.forEach(function(m){var tip=$("tip_"+m.id);if(!tip)return;var d=m.src[m.key];if(d&&(d.desc||d.label)){tip.innerHTML='<span style="color:var(--text2);font-size:.72rem">'+(d.desc||d.label)+"</span>";tip.style.display="block";}else{tip.style.display="none";}});}
