function wireLogTabs(){document.querySelectorAll(".log-tab").forEach(function(t){t.addEventListener("click",function(){document.querySelectorAll(".log-tab").forEach(function(x){x.classList.remove("log-tab-active");});t.classList.add("log-tab-active");var which=t.dataset.log;["logAll","logA","logB"].forEach(function(id){var el=$(id);if(el)el.style.display="none";});var target=which==="all"?"logAll":which==="a"?"logA":"logB";var el=$(target);if(el)el.style.display="block";});});}

function wireModalClose(){["eventModal","compareModal","wpModal"].forEach(function(mid){var closeId="close"+mid.charAt(0).toUpperCase()+mid.slice(1);var closeBtn=$(closeId.replace("Modal","Modal"));if(!closeBtn){var btn=document.getElementById("close"+mid.replace("m","M").replace("odal","odal"));if(btn)btn.addEventListener("click",function(){$(mid).style.display="none";});}});var ce=$("closeEventModal");if(ce)ce.addEventListener("click",function(){$("eventModal").style.display="none";});var cc=$("closeCompareModal");if(cc)cc.addEventListener("click",function(){$("compareModal").style.display="none";});var cw=$("closeWPModal");if(cw)cw.addEventListener("click",function(){$("wpModal").style.display="none";});}

function initApp(){buildApp();var discCB=$("discCB");var discBtn=$("discBtn");if(discCB&&discBtn){discCB.addEventListener("change",function(){discBtn.disabled=!discCB.checked;});discBtn.addEventListener("click",function(){$("disclaimerModal").style.display="none";});}initAccordions();initTooltips();wireProfileChanges();wireInteractionBuilder();wirePracTox();wireBottomBar();wireWPTabs();wireLogTabs();wireModalClose();wireConfigModal();
function wireWizard(){
var wizState={who:null,field:null,step:0,steps:[],scores:{},results:{}};
function openWiz(who,field){wizState.who=who;wizState.field=field;wizState.step=0;wizState.scores={};wizState.results={};
var fields=field?[field]:["mbti","ennea","attach","llGive","conflict","mood","support"];
wizState.steps=[];
for(var i=0;i<fields.length;i++){var f=fields[i];var wKey=f==="ennea"?"ENNEA":f==="attach"?"ATTACH":f==="llGive"||f==="llReceive"?"LL":f==="conflict"?"CONFLICT":f==="mood"?"MOOD":f==="support"?"SUPPORT":f.toUpperCase();
if(D.WIZARD[wKey])wizState.steps.push({field:f,key:wKey,data:D.WIZARD[wKey]});}
if(!wizState.steps.length){N.toast("No wizard available for this field.","info");return;}
$("wizModal").style.display="flex";renderWizStep();}
function renderWizStep(){var st=wizState.steps[wizState.step];if(!st)return;
var prog="";for(var i=0;i<wizState.steps.length;i++){var cls=i<wizState.step?"wiz-dot wiz-dot-done":i===wizState.step?"wiz-dot wiz-dot-active":"wiz-dot";prog+='<div class="'+cls+'"></div>';}$("wizProgress").innerHTML=prog;
$("wizTitle").textContent="\uD83E\uDDD9 "+st.data.title;
var html='<div class="wiz-step"><p>'+st.data.desc+"</p>";
if(!wizState.scores[st.key])wizState.scores[st.key]={};
var qs=st.data.questions;for(var qi=0;qi<qs.length;qi++){html+='<div class="wiz-question"><p>'+(qi+1)+". "+qs[qi].q+'</p><div class="wiz-options">';
for(var ai=0;ai<qs[qi].a.length;ai++){var sel=wizState.scores[st.key]["q"+qi]===ai?"selected":"";html+='<div class="wiz-opt '+sel+'" data-qkey="'+st.key+'" data-qi="'+qi+'" data-ai="'+ai+'">'+qs[qi].a[ai].text+"</div>";}html+="</div></div>";}
html+="</div>";
if(wizState.results[st.key]){var res=wizState.results[st.key];html+='<div class="wiz-result"><h4>Your Result: '+res.label+'</h4><p>'+res.summary+"</p></div>";}
$("wizBody").innerHTML=html;
$("wizPrev").disabled=wizState.step===0;
$("wizNext").textContent=wizState.step>=wizState.steps.length-1?"\u2713 Finish":"Next \u2192";
document.querySelectorAll(".wiz-opt").forEach(function(o){o.addEventListener("click",function(){var qkey=this.dataset.qkey;var qi=parseInt(this.dataset.qi);var ai=parseInt(this.dataset.ai);wizState.scores[qkey]["q"+qi]=ai;
this.parentElement.querySelectorAll(".wiz-opt").forEach(function(x){x.classList.remove("selected");});this.classList.add("selected");
var st2=wizState.steps[wizState.step];var allAnswered=true;for(var i=0;i<st2.data.questions.length;i++){if(wizState.scores[st2.key]["q"+i]===undefined){allAnswered=false;break;}}
if(allAnswered){var totals={};for(var i=0;i<st2.data.questions.length;i++){var chosen=wizState.scores[st2.key]["q"+i];var scoreObj=st2.data.questions[i].a[chosen].score;for(var sk in scoreObj){totals[sk]=(totals[sk]||0)+scoreObj[sk];}}
var result=st2.data.resolve(totals);wizState.results[st2.key]={value:result};
var lbl="";var summary="";
if(st2.key==="MBTI"){lbl=D.MBTI[result]?D.MBTI[result].label:result;summary=D.WIZARD.SUMMARIES.MBTI?D.WIZARD.SUMMARIES.MBTI(result):"";}
else if(st2.key==="ENNEA"){lbl=D.ENNEA[result]?D.ENNEA[result].label:result;summary=D.WIZARD.SUMMARIES.ENNEA?D.WIZARD.SUMMARIES.ENNEA(result):"";}
else if(st2.key==="ATTACH"){lbl=D.ATT[result]?D.ATT[result].label:result;summary=D.WIZARD.SUMMARIES.ATTACH?D.WIZARD.SUMMARIES.ATTACH(result):"";}
else if(st2.key==="LL"){lbl=D.LL_LABELS?D.LL_LABELS[result]||result:result;summary="This is how you naturally express or prefer to receive love.";}
else if(st2.key==="CONFLICT"){lbl=D.CONFLICT[result]?D.CONFLICT[result].label:result;summary="Your default approach to disagreements. This affects how conflicts are processed in the engine.";}
else if(st2.key==="MOOD"){lbl=result.charAt(0).toUpperCase()+result.slice(1);summary="Your current emotional state temporarily influences all interactions.";}
else if(st2.key==="SUPPORT"){lbl=D.getSupportLabel?D.getSupportLabel(result).label:result+"";summary=D.getSupportLabel?D.getSupportLabel(result).desc:"";}
wizState.results[st2.key].label=lbl;wizState.results[st2.key].summary=summary;
renderWizStep();}});});}
$("wizNext").addEventListener("click",function(){var st=wizState.steps[wizState.step];if(wizState.results[st.key]){var val=wizState.results[st.key].value;var who=wizState.who;var s=who==="a"?"A":"B";var field=st.field;
if(field==="mbti"){S[who].mbti=val;var el=$("mbti"+s);if(el)el.value=val;E.setOceanFromMBTI(who);}
else if(field==="ennea"){S[who].ennea=val;var el=$("ennea"+s);if(el)el.value=val;}
else if(field==="attach"){S[who].attach=val;var el=$("attach"+s);if(el)el.value=val;}
else if(field==="llGive"||field==="llReceive"){S[who][field]=val;var el=$(field+s);if(el)el.value=val;}
else if(field==="conflict"){S[who].conflict=val;var el=$("conflict"+s);if(el)el.value=val;}
else if(field==="mood"){S[who].mood=val;var el=$("mood"+s);if(el)el.value=val;}
else if(field==="support"){S[who].support=typeof val==="number"?val:50;var el=$("support"+s);if(el)el.value=S[who].support;}}
if(wizState.step<wizState.steps.length-1){wizState.step++;renderWizStep();}else{$("wizModal").style.display="none";E.recalcAll();renderAll();updateSelTips(wizState.who);N.toast("Wizard complete! Profile updated.","pos");}});
$("wizPrev").addEventListener("click",function(){if(wizState.step>0){wizState.step--;renderWizStep();}});
document.querySelectorAll(".wiz-top-btn").forEach(function(b){b.addEventListener("click",function(){openWiz(this.dataset.who,null);});});
N.openWizField=openWiz;}

wireWizard();E.applyStart();E.initEngine();renderAll();updateSelTips("a");updateSelTips("b");}
document.addEventListener("DOMContentLoaded",initApp);
